	.SBTTL	INTROLABLAPOX	=	78		; coin sup/gaucheLAPOY	=	50;-----------\\; LABYRINTHE >;===========/LABYRINTHE:	LOAD.B	D3,#AFCCMO	LIB	?AFCAR	LOAD.L	A3,#R16"TXIMAS1	CALL	AFIMAGE	JUMP,NE 90$	CALL	CLRFIFO		; vide le FIFO du clavier	LOAD.W	D3,#ICOSOURISD	LOAD.W	D0,D3	LOAD.W	D4,#LAPOY+64*3+26	SWAP.W	D4	LOAD.W	D4,#LAPOX+20	CALL	OPEMOUSE	; jolie p'tite souris	CALL	PMOUSE		; positionne la souris ici	LOAD.L	D5,D4	CLR.L	D6	CLR.W	D110$:	LOAD.W	D3,#ICOSOURISD	; D3 <-- icne si on avance	LOAD.W	D4,D5	COMP.W	D4,D6	JUMP,EQ 15$	JUMP,HI 12$	LOAD.W	D3,#ICOSOURISG	; D3 <-- icne si on recule12$:	COMP.W	D3,D0		; toujours la mme ?	JUMP,EQ 15$		; oui => 15$	INC.W	D1	COMP.W	D1,#5	JUMP,LO 15$	CALL	CLOMOUSE	; enlve l'ancienne souris	LOAD.L	D4,D5	CALL	OPEMOUSE	; met la nouvelle souris	LOAD.W	D0,D3		; D0 <-- dernire icne utilise	CLR.W	D115$:	LOAD.L	D4,D5	CALL	MOVMOUSE	; dplace la souris	LOAD.L	D6,D5		; D6 <-- dernire position	COMP.W	D4,#LAPOX+64*7	JUMP,LO 20$	SWAP.W	D4	COMP.W	D4,#LAPOY+64*3	; est-on dans le fromage (miam) ?	JUMP,HS 80$		; oui => 80$20$:	LIB	?GETKEY		; attend souris ...	COMP.W	D3,#KEYMPO	JUMP,NE 10$	LIB	?IFMOUSE	JUMP,NE 10$	EX.L	D4,D5	CLR.W	D2	LOAD.W	D3,#+1	COMP.W	D4,D5	JUMP',EQ 38$	JUMP',LO 30$	NEG.W	D330$:	ADD.W	D4,D3	CALL	LAIFMUR		; est-on dans un mur ?	JUMP',BC 35$		; non => 35$	SUB.W	D4,D3	LOAD.W	D5,D4	INC.W	D2	JUMP'	38$35$:	COMP.W	D4,D5	JUMP,NE 30$38$:	SWAP.W	D4	SWAP.W	D5	LOAD.W	D3,#+1	COMP.W	D4,D5	JUMP',EQ 48$	JUMP',LO 40$	NEG.W	D340$:	ADD.W	D4,D3	SWAP.W	D4	CALL	LAIFMUR		; est-on dans un mur ?	PUSH.W	F	SWAP.W	D4	POP.W	F	JUMP',BC 45$		; non => 45$	SUB.W	D4,D3	LOAD.W	D5,D4	INC.W	D2	JUMP'	48$45$:	COMP.W	D4,D5	JUMP,NE 40$48$:	SWAP.W	D4	SWAP.W	D5	TEST.W	D2		; collision avec un mur ?	JUMP,EQ 10$		; non => 10$	LOAD.L	D4,D5	CALL	PMOUSE	JUMP	10$80$:				; on-na-ga-gn =>	LOAD.B	D3,#BIPDONE	LIB	?BEEP	LOAD.L	D3,#-1	LOAD.L	D4,D3	LIB	?DRMDEF	LOAD.W	D3,#LAPOY+64*3-12	SWAP.W	D3	LOAD.W	D3,#LAPOX+64*7	LOAD.W	D4,#64+12	SWAP.W	D4	LOAD.W	D4,#64	LOAD.W	D2,#INVDOT	LOAD.W	D1,#10*285$:	PUSH.W	D4	LOAD.W	D4,#4	NTREL	?DELMS	POP.W	D4	LIB	?DRMATRIX	DEC.W	D1	JUMP,NE 85$	CALL	CLOMOUSE	; termine le lutin-p'tite souris90$:	LOAD.B	D3,#AFSCMO	LIB	?AFCAR	RET;--------\\; LAIFMUR >;--------/; Vrifie si l'on est dans un mur.; in	D4.L	position de la souris;	D0.W	ICOSOURISD/G; out	BS/BC	mur/pas mur; mod	-LAIFMUR:	PUSHM.L	D1..D4,A1;;?	COMP.W	D0,#ICOSOURISG;;?	JUMP',EQ 10$	ADD.W	D4,#8;;?10$:	LOAD.W	D3,#(GCICX-8)/820$:	CALL	LAIFMURP	JUMP',BS 90$	ADD.W	D4,#8	DEC.W	D3	JUMP,NE 20$	LOAD.W	D3,#GCICY/830$:	CALL	LAIFMURP	JUMP',BS 90$	SWAP.W	D4	ADD.W	D4,#8	SWAP.W	D4	DEC.W	D3	JUMP,NE 30$	LOAD.W	D3,#(GCICX-8)/840$:	CALL	LAIFMURP	JUMP',BS 90$	SUB.W	D4,#8	DEC.W	D3	JUMP,NE 40$	LOAD.W	D3,#GCICY/850$:	CALL	LAIFMURP	JUMP',BS 90$	SWAP.W	D4	SUB.W	D4,#8	SWAP.W	D4	DEC.W	D3	JUMP,NE 50$	SETZ			; retour BC90$:	POPM.L	D1..D4,A1	RET;---------\\; LAIFMURP >;---------/; Vrifie si l'on est dans un mur.; in	D4.L	position de la souris; out	A1.L	^byte;	D1.B	bit;	BS/BC	mur/pas mur; mod	D1.L, D2.L, A1,LLAIFMURP:	LOAD.L	D2,D4	LOAD.L	A1,#R16"TALABY	SUB.W	D2,#LAPOX	JUMP',LO 80$	SR.W	D2,#3	COMP.W	D2,#8*8	JUMP',HS 80$	SWAP.W	D2	SUB.W	D2,#LAPOY	JUMP',LO 80$	SR.W	D2,#3	COMP.W	D2,#8*4	JUMP',HS 80$	SL.W	D2,#3	ADD.W	A1,D2	SWAP.W	D2	LOAD.W	D1,D2	SR.W	D2,#3	ADD.W	A1,D2	NOT.B	D1	AND.B	D1,#B'111	TEST.B	(A1):D1	JUMP'	90$80$:	CLRZ			; retour BS90$:	RETTALABY:.B	B'11111111,B'11111111,B'11111111,B'11111111,B'11111111,B'11111111,B'11111111,B'11111111.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'00000000.B	B'10000000,B'10000000,B'10000000,B'11111111,B'10000000,B'11111111,B'11111111,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'10000000,B'00000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'11111111,B'11111111,B'10000000,B'11111111,B'11111111,B'10000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'00000000,B'00000000,B'00000000,B'10000000.B	B'11111111,B'11111111,B'10000000,B'10000000,B'11111111,B'11111111,B'10000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000.B	B'10000000,B'00000000,B'00000000,B'10000000,B'10000000,B'00000000,B'00000000,B'10000000	.END